class Solution {
    public long findMaximumNumber(long k, int x) {
        long left = 0, right = (long) (k * x);
        while (left < right) {
            long mid = left + (right - left + 1) / 2;
            if (getPrice(mid, x) <= k) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

    private long getPrice(long num, int x) {
        long price = 0;
        for (long i = 1; i <= num; i++) {
            long n = i;
            while (n > 0) {
                if ((n % (1L << x) == 0) && (n & (1L << (x - 1))) != 0) {
                    price++;
                }
                n >>= x;
            }
        }
        return price;
    }
}
