class Solution {
    public long findMaximumNumber(long k, int x) {
        long left = 0, right = (long) (k * x);
        while (left < right) {
            long mid = left + (right - left + 1) / 2;
            if (countSetBits(mid, x) <= k) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

    private long countSetBits(long num, int x) {
        long count = 0;
        for (int i = x; i <= 64; i += x) {
            long mask = (1L << i) - 1;
            count += (num >> i) * (1L << (i - 1)) + Math.max(0, (num & mask) - ((1L << (i - 1)) - 1));
        }
        return count;
    }
}
